// ClaimHeartbeatExtraKey is the Extra key for the work heartbeat
// timestamp. It is cleared by both Unclaim and Reopen but is kept separate
// from ClaimMetadataExtraKeys because its cleanup semantics differ in some
// call sites (e.g. SetExecutionCooldown does not touch it).
const ClaimHeartbeatExtraKey = "work-heartbeat-at"

// ClearClaimStateExtra removes all claim-related keys from the Extra map.
// This reverses the claim metadata set by Claim operations and is called
// when a bead's claim is released (Unclaim, Reopen) or when migrating away
// from tracked claim metadata (external heartbeat leases replaced tracked
// timestamps in the bead row). Both ClaimMetadataExtraKeys and the heartbeat
// key represent temporary worker state that should not persist after claim
// release.
func ClearClaimStateExtra(extra map[string]any) {
	if extra == nil {
		return
	}
	for _, k := range ClaimMetadataExtraKeys {
		delete(extra, k)
	}
	delete(extra, ClaimHeartbeatExtraKey)
}

